const $=document.querySelector.bind(document),TRANSLATE={att:"攻",def:"守",sto:"偷"};function sleep(t){return new Promise((e=>setTimeout(e,t)))}function randPick(t){let e=0;for(let n of Object.keys(t))e+=t[n];let n=Math.random()*e;for(let e of Object.keys(t))if(n-=t[e],n<=0)return e}function dialog(t,e,n="确定",o="取消"){return new Promise((r=>{Swal.fire({title:t,text:e,showDenyButton:!0,confirmButtonText:n,denyButtonText:o}).then((t=>{t.isConfirmed&&r(!0),r(!1)}))}))}function arrayShuffle(t){let e=[...t];for(let t=e.length-1;t>0;t--){let n=Math.floor(Math.random()*(t+1));[e[t],e[n]]=[e[n],e[t]]}return e}